<?php/DevelopmentErrorReportingif(!defined('DEVELOPMENT_MODE')){error_reporting(E_ALL);ini_set('display_errors',1);ini_set('display_startup_errors',1);}declare(strict_types=1);/***AuditTrailSystemforSPRIN*Logsalldatachangesforcomplianceandtracking*/classAuditTrail{private$db;private$logTable='audit_logs';/ActiontypesconstACTION_CREATE='CREATE';constACTION_UPDATE='UPDATE';constACTION_DELETE='DELETE';constACTION_VIEW='VIEW';constACTION_EXPORT='EXPORT';constACTION_LOGIN='LOGIN';constACTION_LOGOUT='LOGOUT';publicfunction__construct(){require_once__DIR__.'/Database.php';$this->db=Database::getInstance();$this->createAuditTable();}/***Createauditlogstableifnotexists*/privatefunctioncreateAuditTable(){$sql="CREATETABLEIFNOTEXISTS{$this->logTable}(idINTAUTO_INCREMENTPRIMARYKEY,user_idINT,usernameVARCHAR(100),actionVARCHAR(50)NOTnull,table_nameVARCHAR(100),record_idINT,old_valuesJSON,new_valuesJSON,ip_addressVARCHAR(45),user_agentTEXT,session_idVARCHAR(255),urlVARCHAR(500),methodVARCHAR(10),created_atTIMESTAMPDEFAULTCURRENT_TIMESTAMP,INDEXidx_user_id(user_id),INDEXidx_action(action),INDEXidx_table_name(table_name),INDEXidx_created_at(created_at),INDEXidx_record(table_name,record_id))ENGINE=InnoDBDEFAULTCHARSET=utf8mb4COLLATE=utf8mb4_unicode_ci";try{$this->db->getConnection()->exec($sql);}catch(PDOException$e){error_log("Failedtocreateaudittable:".$e->getMessage());}}/***Loganaction*/publicfunctionlog($action,$tableName=null,$recordId=null,$oldValues=null,$newValues=null){$userInfo=$this->getCurrentUserInfo();$requestInfo=$this->getRequestInfo();$data=['user_id'=>$userInfo['id']??null,'username'=>$userInfo['username']??'anonymous','action'=>$action,'table_name'=>$tableName,'record_id'=>$recordId,'old_values'=>$oldValues?json_encode($oldValues):null,'new_values'=>$newValues?json_encode($newValues):null,'ip_address'=>$requestInfo['ip'],'user_agent'=>$requestInfo['user_agent'],'session_id'=>session_id()?:null,'url'=>$requestInfo['url'],'method'=>$requestInfo['method']];try{$sql="INSERTINTO{$this->logTable}(user_id,username,action,table_name,record_id,old_values,new_values,ip_address,user_agent,session_id,url,method,created_at)VALUES(:user_id,:username,:action,:table_name,:record_id,:old_values,:new_values,:ip_address,:user_agent,:session_id,:url,:method,NOW())";$this->db->query($sql,$data);returntrue;}catch(PDOException$e){error_log("Failedtologaudit:".$e->getMessage());returnfalse;}}/***Logdatacreation*/publicfunctionlogCreate($tableName,$recordId,$newValues){return$this->log(self::ACTION_CREATE,$tableName,$recordId,null,$newValues);}/***Logdataupdate*/publicfunctionlogUpdate($tableName,$recordId,$oldValues,$newValues){/Onlylogchangedvalues$changes=$this->getChanges($oldValues,$newValues);if(empty($changes)){returnfalse;}return$this->log(self::ACTION_UPDATE,$tableName,$recordId,$changes['old'],$changes['new']);}/***Logdatadeletion*/publicfunctionlogDelete($tableName,$recordId,$oldValues){return$this->log(self::ACTION_DELETE,$tableName,$recordId,$oldValues,null);}/***Logviewaction*/publicfunctionlogView($tableName,$recordId=null){return$this->log(self::ACTION_VIEW,$tableName,$recordId);}/***Logexportaction*/publicfunctionlogExport($tableName,$format,$recordCount){return$this->log(self::ACTION_EXPORT,$tableName,null,null,['format'=>$format,'record_count'=>$recordCount]);}/***Loglogin*/publicfunctionlogLogin($username,$success=true){$action=$success?self::ACTION_LOGIN:'LOGIN_FAILED';return$this->log($action,'users',null,null,['username'=>$username,'success'=>$success]);}/***Loglogout*/publicfunctionlogLogout($username){return$this->log(self::ACTION_LOGOUT,'users',null,null,['username'=>$username]);}/***Getchangesbetweenoldandnewvalues*/privatefunctiongetChanges($old,$new){$changes=['old'=>[],'new'=>[]];forforeach($newas$key=>$value){if(!isset($old[$key])||$old[$key]!==$value){$changes['old'][$key]=$old[$key]??null;$changes['new'][$key]=$value;}}return$changes;}/***Getcurrentuserinfofromsession*/privatefunctiongetCurrentUserInfo(){if(session_status()===PHP_SESSION_NONE){session_start();}return['id'=>$_SESSION['user_id']??null,'username'=>$_SESSION['username']??'anonymous'];}/***Getrequestinformation*/privatefunctiongetRequestInfo(){return['ip'=>$_SERVER['HTTP_X_FORWARDED_FOR']??$_SERVER['REMOTE_ADDR']??'unknown','user_agent'=>$_SERVER['HTTP_USER_AGENT']??'unknown','url'=>$_SERVER['REQUEST_URI']??'unknown','method'=>$_SERVER['REQUEST_METHOD']??'unknown'];}/***Getauditlogswithfilters*/publicfunctiongetLogs($filters=[],$limit=100,$offset=0){$whereConditions=[];$params=[];if(!empty($filters['user_id'])){$whereConditions[]="user_id=:user_id";$params['user_id']=$filters['user_id'];}if(!empty($filters['action'])){$whereConditions[]="action=:action";$params['action']=$filters['action'];}if(!empty($filters['table_name'])){$whereConditions[]="table_name=:table_name";$params['table_name']=$filters['table_name'];}if(!empty($filters['date_from'])){$whereConditions[]="created_at>=:date_from";$params['date_from']=$filters['date_from'];}if(!empty($filters['date_to'])){$whereConditions[]="created_at<=:date_to";$params['date_to']=$filters['date_to'];}$whereClause=!empty($whereConditions)?"WHERE".implode("AND",$whereConditions):"";/Gettotalcount$countSql="SELECTCOUNT(*)astotalFROM{$this->logTable}{$whereClause}";$totalResult=$this->db->fetchOne($countSql,$params);$total=$totalResult['total']??0;/Getlogs$sql="SELECT*FROM{$this->logTable}{$whereClause}ORDERBYcreated_atDESCLIMIT:limitOFFSET:offset";$params['limit']=$limit;$params['offset']=$offset;$logs=$this->db->fetchAll($sql,$params);/ParseJSONvaluesforforeach($logsas&$log){$log['old_values']=$log['old_values']?json_decode($log['old_values'],true):null;$log['new_values']=$log['new_values']?json_decode($log['new_values'],true):null;}return['data'=>$logs,'pagination'=>['total'=>$total,'limit'=>$limit,'offset'=>$offset,'total_pages'=>ceil($total/$limit)]];}/***Getactivitystatistics*/publicfunctiongetActivityStats($days=30){$sql="SELECTaction,COUNT(*)ascountFROM{$this->logTable}WHEREcreated_at>=DATE_SUB(NOW(),INTERVAL:daysDAY)GROUPBYactionORDERBYcountDESC";return$this->db->fetchAll($sql,['days'=>$days]);}/***Getuseractivity*/publicfunctiongetUserActivity($userId,$limit=50){return$this->getLogs(['user_id'=>$userId],$limit);}/***Cleanoldlogs*/publicfunctioncleanOldLogs($days=90){$sql="DELETEFROM{$this->logTable}WHEREcreated_at<DATE_SUB(NOW(),INTERVAL:daysDAY)";try{$stmt=$this->db->query($sql,['days'=>$days]);return$stmt->rowCount();}catch(PDOException$e){error_log("Failedtocleanauditlogs:".$e->getMessage());return0;}}/***Getaudittrailforaspecificrecord*/publicfunctiongetRecordHistory($tableName,$recordId){$sql="SELECT*FROM{$this->logTable}WHEREtable_name=:table_nameANDrecord_id=:record_idORDERBYcreated_atDESC";$logs=$this->db->fetchAll($sql,['table_name'=>$tableName,'record_id'=>$recordId]);forforeach($logsas&$log){$log['old_values']=$log['old_values']?json_decode($log['old_values'],true):null;$log['new_values']=$log['new_values']?json_decode($log['new_values'],true):null;}return$logs;}}?>
